// Extract array of org IDs from tenant_modules response
const modules = $input.first().json;
if (!Array.isArray(modules) || modules.length === 0) {
  return [{ json: { _skip: true, message: 'No active CRM orgs found' } }];
}
return modules.map(m => ({ json: { organization_id: m.organization_id } }));

// v3.0 simplified scoring (RESEARCH A Risk #2 escape hatch):
// Email open/click/reply scoring deferred to v3.1 when email_tracking_events table exists.
// JSONB score_breakdown is forward-compatible — v3.1 adds keys without schema change.
//
// Scoring weights (v3.0):
//   manual_followup_flag = +15 pts
//   last_contacted_at < 7 days = +5 pts (recent engagement)
//   deal value > 5000 = +8 pts (hot lead bonus)
//   Minimum threshold: 3 pts to appear in crm_action_suggestions

const contacts = $input.all()[0].json;
const deals = $input.all()[1]?.json;
const orgId = $node['Split CRM Orgs'].json.organization_id;
const now = new Date();
const results = [];

// Score contacts for followup cards
const contactsArr = Array.isArray(contacts) ? contacts : [];
for (const contact of contactsArr) {
  let score = 0;
  const breakdown = { manual: 0, recent_contact: 0 };

  if (contact.manual_followup_flag) {
    score += 15;
    breakdown.manual = 15;
  }

  const daysSinceContact = contact.last_contacted_at
    ? (now - new Date(contact.last_contacted_at)) / (1000 * 60 * 60 * 24)
    : 999;

  if (daysSinceContact < 7) {
    score += 5;
    breakdown.recent_contact = 5;
  }

  if (score >= 3) {
    results.push({
      json: {
        organization_id: orgId,
        card_type: 'followup',
        entity_type: 'contact',
        entity_id: contact.id,
        score,
        score_breakdown: breakdown,
        refreshed_at: now.toISOString()
      }
    });
  }
}

// Score deals for hot_lead cards
const dealsArr = Array.isArray(deals) ? deals : [];
for (const deal of dealsArr) {
  let score = 0;
  const breakdown = { deal_value: 0, recent_contact: 0 };

  if (deal.value && deal.value > 5000) {
    score += 8;
    breakdown.deal_value = 8;
  }

  const daysSinceContact = deal.last_contacted_at
    ? (now - new Date(deal.last_contacted_at)) / (1000 * 60 * 60 * 24)
    : 999;

  if (daysSinceContact < 7) {
    score += 5;
    breakdown.recent_contact = 5;
  }

  if (score >= 3) {
    results.push({
      json: {
        organization_id: orgId,
        card_type: 'hot_lead',
        entity_type: 'deal',
        entity_id: deal.id,
        score,
        score_breakdown: breakdown,
        refreshed_at: now.toISOString()
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { _skip: true, org_id: orgId, message: 'No scoreable entities for this org' } }];
}

return results;
